%% Design checklist
%% 1) Which states can fail? Add error_transition for each non-terminal state.
%% 2) Which states hold timers/file handles/locks? Add requires_cleanup and cleanup_on_transition.
%% 3) Are there explicit exit points (process.exit/throw/return)? Model as terminal or error_transition.
%% 4) If async wait is involved, define timeout/error path so waits cannot hang silently.
%% 5) If a state reads async data, define writes() path before reads() and guard races.

transition(storage_flow, idle, connecting).
transition(storage_flow, connecting, connected).
transition(storage_flow, connected, reading).
transition(storage_flow, connected, writing).
transition(storage_flow, reading, connected).
transition(storage_flow, writing, connected).
error_transition(storage_flow, connecting, error).
error_transition(storage_flow, reading, error).
error_transition(storage_flow, writing, error).
error_transition(storage_flow, connected, quota_exceeded).
error_transition(storage_flow, reading, corrupted).
error_transition(storage_flow, writing, corrupted).
transition(storage_flow, error, cleanup).
transition(storage_flow, quota_exceeded, cleanup).
transition(storage_flow, corrupted, cleanup).
transition(storage_flow, cleanup, idle).
transition(indexeddb_flow, idle, opening_db).
transition(indexeddb_flow, opening_db, creating_stores).
transition(indexeddb_flow, creating_stores, db_open).
