transition(indexeddb_flow, transaction_start, writing).
transition(indexeddb_flow, reading, committing).
transition(indexeddb_flow, writing, committing).
transition(indexeddb_flow, committing, db_open).
error_transition(indexeddb_flow, opening_db, error).
error_transition(indexeddb_flow, creating_stores, error).
error_transition(indexeddb_flow, reading, error).
error_transition(indexeddb_flow, writing, error).
error_transition(indexeddb_flow, committing, error).
error_transition(indexeddb_flow, db_open, quota_exceeded).
error_transition(indexeddb_flow, transaction_start, db_corrupted).
error_transition(indexeddb_flow, reading, db_corrupted).
error_transition(indexeddb_flow, writing, db_corrupted).
transition(indexeddb_flow, error, cleanup).
transition(indexeddb_flow, quota_exceeded, cleanup).
transition(indexeddb_flow, db_corrupted, cleanup).
transition(indexeddb_flow, cleanup, idle).
